const [completedTopics, setCompletedTopics] = useState<string[]>([]);
const [isCustomTopic, setIsCustomTopic] = useState<boolean>(false);
const [customTopic, setCustomTopic] = useState<string>("");
const [isLibraryModalOpen, setIsLibraryModalOpen] = useState<boolean>(false);

const res = await fetch("/api/quiz/topics");
if (res.ok) {
  const data = await res.json();
  if (data.success && data.topics) {
    const serverTopics = data.topics as {id: string, count: number}[];
    const merged = [...defaultTopics];
    for (const st of serverTopics) {
      const existing = merged.find(t => t.id === st.id);
      if (!existing) {
        merged.push({
          id: st.id,
          icon: BookOpen,
          title: st.id.replace(/_/g, ' ').toUpperCase(),
          desc: lang === "vi" ? "Chủ đề tự tạo từ Admin" : "Admin Custom Topic",
          count: st.count
        });
      } else {
        (existing as any).count = st.count;
      }
    }
    setTopics(merged);
  }
}

